// Parsear respuestas del guion y SEO
const scriptResponse = $('✍️ Generar guion (OpenRouter)').item.json;
const seoResponse = $('🏷️ Generar SEO (OpenRouter)').item.json;
const topic = $('📋 Obtener tópicos pendientes').item.json;

// Extraer guion
const fullScript = scriptResponse.choices?.[0]?.message?.content?.trim();
if (!fullScript) {
  throw new Error('El LLM no generó guion válido para: ' + topic.topic);
}

const wordCount = fullScript.split(/\s+/).length;
const estimatedDuration = wordCount / 3.2; // ~3.2 palabras por segundo en narración

// Extraer SEO
let seoData = {};
try {
  const seoContent = seoResponse.choices?.[0]?.message?.content || '{}';
  seoData = JSON.parse(seoContent);
} catch (e) {
  console.warn('Error parseando SEO, usando defaults:', e.message);
  seoData = {
    youtube_title: topic.topic.substring(0, 60),
    youtube_description: topic.summary || '',
    hashtags: ['truecrime', 'crimenesreales', 'shorts'],
    tiktok_title: topic.topic.substring(0, 50),
    keywords: [topic.topic],
    thumbnail_text: 'INCREÍBLE CASO REAL'
  };
}

// Calcular costo estimado (gpt-4o-mini: ~$0.00015/1K input, $0.0006/1K output)
const promptTokens = scriptResponse.usage?.prompt_tokens || 0;
const completionTokens = scriptResponse.usage?.completion_tokens || 0;
const costUsd = (promptTokens * 0.00015 / 1000) + (completionTokens * 0.0006 / 1000);

return [{
  json: {
    topic_id: topic.id,
    topic: topic.topic,
    full_script: fullScript,
    word_count: wordCount,
    estimated_duration_s: Math.round(estimatedDuration * 10) / 10,
    title: seoData.youtube_title || topic.topic,
    description: seoData.youtube_description || '',
    hashtags: seoData.hashtags || [],
    keywords: seoData.keywords || [],
    tiktok_title: seoData.tiktok_title || '',
    thumbnail_text: seoData.thumbnail_text || '',
    model_used: 'gpt-4o-mini',
    prompt_tokens: promptTokens,
    completion_tokens: completionTokens,
    cost_usd: costUsd
  }
}];

